function patientTemplate(input) {
  return {
    id:input.id,scenarioId:input.scenarioId||'scratch',firstName:input.firstName,lastName:input.lastName,age:input.age||'--',sex:input.sex||'--',dob:input.dob||'--',mrn:input.mrn||randomMrn(),
    location:input.location||'Simulation room',encounter:input.encounter||'Simulation encounter',diagnosis:input.diagnosis||'Practice case',acuity:input.acuity||'Stable',codeStatus:input.codeStatus||'Full Code',allergies:input.allergies||'NKDA',attending:input.attending||'Simulation provider',nurse:'Student Nurse',
    specialty:input.specialty||'Student-created',tags:input.tags||['HCT'],gestation:input.gestation||'N/A',height:input.height||'--',weight:input.weight||'--',diet:input.diet||'As ordered',activity:input.activity||'As tolerated',lines:input.lines||'Add line/access details',monitoring:input.monitoring||'As ordered',
    chiefComplaint:input.chiefComplaint||input.diagnosis||'Practice case',hpi:input.hpi||'Add HPI details.',background:input.background||'Add background and relevant history.',pastHistory:input.pastHistory||'Add past medical history.',social:input.social||'Add support system and social history.',familyContact:input.familyContact||'Add family/contact details.',
    objectives:input.objectives||['Complete chart review.','Document focused assessment.','Chart interventions and patient response.','Use SBAR for priority communication.'],
    orders:(input.orders||[]).map(([category,order,details,status])=>({category,order,details,status})),
    labs:(input.labs||[]).map(([time,test,result,range,flag,note])=>({time,test,result,range,flag,note})),
    diagnostics:input.diagnostics||[],vitals:input.vitals||[],
    meds:(input.meds||[]).map(([name,dose,route,freq,priority,status,warn],index)=>({id:`med-${index}-${Date.now()}`,name,dose,route,freq,priority,status,time:'',note:'',warn})),
    io:input.io||[],notes:[],
    assessment:input.assessment||{neuro:'',resp:'',cardiac:'',gi:'',gu:'',skin:'',safety:'',pain:'',specialty:'',psychosocial:'',narrative:''},
    carePlan:input.carePlan||[{dx:'',goal:'',interventions:'',evaluation:'Pending'}],
    education:input.education||[{topic:'Diagnosis and plan of care',status:'Not started',response:''}],
    sbar:{s:'',b:'',a:'',r:''},
    reasoningResponses:input.reasoningResponses||{},
    debriefing:input.debriefing||{selfScore:'',strengths:'',improvements:'',facilNotes:'',submitted:false},
    peerReviews:input.peerReviews||[],
    facultyModules:input.facultyModules||[],
    interactionLog:input.interactionLog||[]
  };
}

function randomMrn(){return String(Math.floor(100000+Math.random()*900000));}
function clone(v){return JSON.parse(JSON.stringify(v));}
function esc(v){return String(v??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}
function lines(v){return esc(v||'').replace(/\n/g,'<br>');}
function nowTime(){return new Date().toTimeString().slice(0,5);}
function uid(p){return `${p}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2,7)}`;}

const I18N={
  en:{appTitle:'HCT Student EHR Simulation',tagline:'Interactive EHR practice with peer review, printable reports, and faculty-built modules',dark:'Dark mode',light:'Light mode',lang:'Tagalog',printReport:'Print report',peer:'Peer review mode',faculty:'Faculty module builder'},
  tl:{appTitle:'HCT Student EHR Simulation',tagline:'Interaktibong pagsasanay sa EHR na may peer review, ulat na napi-print, at module ng faculty',dark:'Madilim',light:'Maliwanag',lang:'English',printReport:'I-print ang ulat',peer:'Peer review',faculty:'Tagabuo ng module'}
};
function settings(){if(!state.settings)state.settings={theme:'light',language:'en',interactive:true};return state.settings;}
function tr(k){const lang=settings().language||'en';return(I18N[lang]&&I18N[lang][k])||I18N.en[k]||k;}
function applyTheme(){document.documentElement.dataset.theme=settings().theme==='dark'?'dark':'light';document.documentElement.lang=settings().language==='tl'?'tl':'en';}
function logInteraction(action){const p=currentPatient();if(!p.interactionLog)p.interactionLog=[];p.interactionLog.unshift({time:new Date().toLocaleString(),action});p.interactionLog=p.interactionLog.slice(0,12);}
function chartStats(p){return{vitals:p.vitals?.length||0,notes:p.notes?.length||0,meds:(p.meds||[]).filter(m=>m.status==='given').length,care:(p.carePlan||[]).filter(c=>String(c.evaluation||'').toLowerCase().includes('met')||String(c.evaluation||'').toLowerCase().includes('progress')).length,education:(p.education||[]).filter(e=>e.status==='Complete').length,peer:p.peerReviews?.length||0,modules:p.facultyModules?.length||0};}
function completionScore(p){const c=chartStats(p);return Math.min(100,Math.round(((c.vitals>0)+(c.notes>0)+(c.meds>0)+(c.care>0)+(c.education>0)+(!!p.sbar?.s)+(Object.keys(p.reasoningResponses||{}).length>0)+(c.peer>0))*12.5));}

let state=loadState();
let dashboardRows=[];
let dashboardSelectedId='';
let saveTimer=null;
let cloud={ready:false,client:null,session:null,profile:null,status:'Local only',busy:false};

function loadState(){
   try{const s=JSON.parse(localStorage.getItem(LOCAL_KEY)||'null');if(s&&Array.isArray(s.patients)&&s.patients.length){s.settings=s.settings||{theme:'light',language:'en',interactive:true};s.patients.forEach(p=>{p.peerReviews=p.peerReviews||[];p.facultyModules=p.facultyModules||[];p.interactionLog=p.interactionLog||[];});return s;}}catch(e){}
  return{patients:[clone(scenarios[0].patient)],activeId:'heg-default',tab:'summary',submitted:{},settings:{theme:'light',language:'en',interactive:true}};
}
function currentPatient(){return state.patients.find(p=>p.id===state.activeId)||state.patients[0];}
function scenarioName(id){return(scenarios.find(s=>s.id===id)||{}).name||'Student-created case';}
function toast(msg){const el=document.getElementById('toast');el.textContent=msg;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2200);}
function persist(opts={}){applyTheme();localStorage.setItem(LOCAL_KEY,JSON.stringify(state));if(opts.cloud!==false)scheduleCloudSave();}
function scheduleCloudSave(){if(!cloud.ready||!cloud.session)return;clearTimeout(saveTimer);saveTimer=setTimeout(()=>saveCurrentChart(false),1200);}

function badgeClass(t){const s=String(t||'').toLowerCase();if(s.includes('allergy')||s.includes('fall')||s.includes('critical')||s.includes('stat'))return'red';if(s.includes('npo')||s.includes('risk')||s.includes('watch')||s.includes('safety')||s.includes('elopement'))return'gold';if(s.includes('stable')||s.includes('full code'))return'green';if(s.includes('hct'))return'teal';return'blue';}
function statusClass(t){const s=String(t||'').toLowerCase();if(s.includes('stat')||s.includes('critical')||s.includes('high')||s.includes('low'))return'critical';if(s.includes('pending')||s.includes('hold'))return'pending';if(s.includes('active')||s.includes('complete')||s.includes('given'))return'done';return'normal';}
function section(title,body,right=''){return `<div class="card"><div class="card-head"><h3>${esc(title)}</h3>${right}</div><div class="card-body">${body}</div></div>`;}
function field(label,value){return `<div class="field"><span class="k">${esc(label)}</span><span class="v">${lines(value||'--')}</span></div>`;}

async function initSupabase(){
  const cfg=window.HCT_SUPABASE_CONFIG||{};
  const ok=cfg.url&&cfg.anonKey&&!cfg.url.includes('YOUR-')&&!cfg.anonKey.includes('YOUR_');
  if(!ok||!window.supabase){cloud.status='Supabase not configured';render();return;}
  cloud.ready=true;
  cloud.client=window.supabase.createClient(cfg.url,cfg.anonKey);
  const{data}=await cloud.client.auth.getSession();
  cloud.session=data.session;
  if(cloud.session)await loadProfile();
  cloud.client.auth.onAuthStateChange(async(_,session)=>{cloud.session=session;cloud.profile=null;if(session)await loadProfile();render();});
  cloud.status=cloud.session?'Cloud connected':'Ready for login';
  render();
}
async function loadProfile(){
  if(!cloud.session)return;
  const u=cloud.session.user;
  const{data}=await cloud.client.from('profiles').select('*').eq('id',u.id).maybeSingle();
  if(data){cloud.profile=data;return;}
  const m=u.user_metadata||{};
  const p={id:u.id,email:u.email,full_name:m.full_name||'',student_id:m.student_id||'',section:m.section||'',role:'student'};
  await cloud.client.from('profiles').insert(p);cloud.profile=p;
}
async function signIn(){const e=val('auth-email'),p=val('auth-password');if(!e||!p){toast('Email and password required');return;}cloud.status='Signing in...';render();const{error}=await cloud.client.auth.signInWithPassword({email:e,password:p});if(error){cloud.status='Sign in failed';toast(error.message);render();return;}toast('Signed in');}
async function signUp(){const e=val('auth-email'),p=val('auth-password');if(!e||!p){toast('Email and password required');return;}const m={full_name:val('auth-name'),student_id:val('auth-student-id'),section:val('auth-section')};cloud.status='Creating account...';render();const{data,error}=await cloud.client.auth.signUp({email:e,password:p,options:{data:m}});if(error){cloud.status='Account creation failed';toast(error.message);render();return;}if(data.session){cloud.session=data.session;await upsertProfile(m);toast('Student account ready');}else toast('Check email to confirm the account');render();}
async function upsertProfile(m={}){if(!cloud.session)return;const u=cloud.session.user;const r=cloud.profile?.role||'student';const p={id:u.id,email:u.email,full_name:m.full_name||cloud.profile?.full_name||'',student_id:m.student_id||cloud.profile?.student_id||'',section:m.section||cloud.profile?.section||'',role:r};const{error}=await cloud.client.from('profiles').upsert(p,{onConflict:'id'});if(error)toast(error.message);else cloud.profile=p;}
async function signOut(){await cloud.client.auth.signOut();cloud.session=null;cloud.profile=null;cloud.status='Signed out';toast('Signed out');render();}

function chartRecord(status){
  const p=currentPatient();const prof=cloud.profile||{};const submitted=status==='submitted'||state.submitted[p.id];
  return{user_id:cloud.session.user.id,local_patient_id:p.id,scenario_id:p.scenarioId,scenario_name:scenarioName(p.scenarioId),patient_name:`${p.lastName}, ${p.firstName}`,patient_mrn:p.mrn,student_name:prof.full_name||cloud.session.user.email,student_id:prof.student_id||'',section:prof.section||'',status:submitted?'submitted':'draft',submitted_at:submitted?new Date().toISOString():null,chart:{patient:p,saved_at:new Date().toISOString()}};
}
async function saveCurrentChart(showToast=true,status='draft'){
  if(!cloud.ready||!cloud.session){if(showToast)toast('Sign in to save centrally');return;}
  const rec=chartRecord(status);const{error}=await cloud.client.from('chart_attempts').upsert(rec,{onConflict:'user_id,local_patient_id'});
  if(error){cloud.status='Cloud save failed';if(showToast)toast(error.message);}else{cloud.status=rec.status==='submitted'?'Submitted to instructor':'Saved to Supabase';if(showToast)toast(cloud.status);}
  renderCloudOnly();
}
async function submitCurrentChart(){if(!cloud.session){toast('Sign in before submitting');return;}if(!confirm('Submit this chart for instructor review?'))return;state.submitted[currentPatient().id]=true;persist({cloud:false});await saveCurrentChart(true,'submitted');}
async function fetchDashboard(){
  if(!cloud.profile||cloud.profile.role!=='instructor')return;
  cloud.status='Loading dashboard...';renderCloudOnly();
  const{data,error}=await cloud.client.from('chart_attempts').select('id,updated_at,submitted_at,status,student_name,student_id,section,scenario_name,patient_name,patient_mrn,chart,review_score,review_comment').order('updated_at',{ascending:false}).limit(200);
  if(error){toast(error.message);return;}dashboardRows=data||[];cloud.status=`Dashboard loaded: ${dashboardRows.length} charts`;render();
}
async function saveReview(id){
  const score=val(`review-score-${id}`);const comment=val(`review-comment-${id}`);
  const{error}=await cloud.client.from('chart_attempts').update({review_score:score?Number(score):null,review_comment:comment,reviewed_at:new Date().toISOString(),reviewed_by:cloud.session.user.id}).eq('id',id);
  if(error)toast(error.message);else{toast('Review saved');await fetchDashboard();}
}

function render(){
  applyTheme();
  const p=currentPatient();
  document.getElementById('app').innerHTML=`
    <div class="app-shell">
      <header class="topbar">
        <div class="brand"><img class="logo" src="${LOGO_TEAL}" alt="HCT logo"><div><h1>${tr('appTitle')}</h1><p>${tr('tagline')}</p></div></div>
        <div class="top-actions"><div><strong>${cloud.profile?esc(cloud.profile.full_name||cloud.profile.email):'HCT Simulation Program'}</strong><p>${esc(cloud.status)}</p></div><button class="btn small" id="theme-toggle">${settings().theme==='dark'?tr('light'):tr('dark')}</button><button class="btn small" id="lang-toggle">${tr('lang')}</button><img class="logo small" src="${LOGO_NAVY}" alt="HCT logo navy"></div>
      </header>
      ${renderCloudPanel()}
      <div id="alert-banner"></div>
      <div class="ehr">
         <aside class="sidebar">${renderPatientCard(p)}${renderPatientTools()}${renderNav()}<div class="sidebar-foot">${cloud.profile?`${esc(cloud.profile.role)} | ${esc(cloud.profile.section||'No section')}`:'Local practice mode'}<br>HCT EHR v3 — interactive build</div></aside>
        <main class="main"><div class="toolbar"><div class="toolbar-title"><h2>${esc(tabTitle())}</h2><p>${esc(p.lastName)}, ${esc(p.firstName)} | MRN ${esc(p.mrn)} | ${esc(cloud.status)}</p></div>${toolbarButtons()}</div><section class="content" id="content">${renderTab()}</section></main>
      </div>
    </div>`;
  bindEvents();
}
function renderCloudOnly(){const panel=document.getElementById('cloud-panel');if(panel)panel.outerHTML=renderCloudPanel();const sub=document.querySelector('.toolbar-title p');if(sub){const p=currentPatient();sub.textContent=`${p.lastName}, ${p.firstName} | MRN ${p.mrn} | ${cloud.status}`;}bindCloudEvents();}
function renderCloudPanel(){
  if(!cloud.ready)return`<section class="cloud-panel" id="cloud-panel"><div class="notice danger"><span class="mark">SETUP</span><span>Supabase not configured. Fill in supabase-config.js and run supabase-schema.sql.</span></div></section>`;
  if(!cloud.session)return`<section class="cloud-panel" id="cloud-panel"><div class="cloud-grid"><div><span class="input-label">Email</span><input id="auth-email" type="email" placeholder="student@example.edu"></div><div><span class="input-label">Password</span><input id="auth-password" type="password" placeholder="Password"></div><div><span class="input-label">Full name</span><input id="auth-name" placeholder="Student name"></div><div><span class="input-label">Student ID</span><input id="auth-student-id" placeholder="ID"></div><div><span class="input-label">Section</span><input id="auth-section" placeholder="Class/section"></div></div><div class="actions"><button class="btn" id="signin-btn">Sign in</button><button class="btn primary" id="signup-btn">Create student account</button></div></section>`;
  const p=cloud.profile||{};
  return`<section class="cloud-panel" id="cloud-panel"><div class="cloud-status"><span class="badge ${p.role==='instructor'?'navy':'teal'}">${esc(p.role||'student')}</span><strong>${esc(p.full_name||cloud.session.user.email)}</strong><span>${esc(p.student_id||'')}</span><span>${esc(p.section||'')}</span><span>${esc(cloud.status)}</span></div><div class="actions"><button class="btn primary" id="save-cloud-btn">Save chart</button><button class="btn navy" id="submit-chart-btn">Submit chart</button>${p.role==='instructor'?'<button class="btn" id="dashboard-shortcut">Instructor dashboard</button>':''}<button class="btn" id="signout-btn">Sign out</button></div></section>`;
}

function renderPatientCard(p){
  const showG=p.gestation&&p.gestation!=='N/A';
  return`<div class="patient-card"><span class="label">Active patient</span><div class="patient-name">${esc(p.lastName)}, ${esc(p.firstName)}</div><div class="patient-line">${esc(p.sex)} | ${esc(p.age)}y | DOB ${esc(p.dob)} | MRN ${esc(p.mrn)}</div><div class="patient-line">${esc(p.location)} | ${esc(p.diagnosis)}</div>${showG?`<div class="patient-line">${esc(p.gestation)} | ${esc(p.codeStatus)} | ${esc(p.allergies)}</div>`:`<div class="patient-line">${esc(p.codeStatus)} | ${esc(p.allergies)}</div>`}<div class="badges">${(p.tags||[]).map(t=>`<span class="badge ${badgeClass(t)}">${esc(t)}</span>`).join('')}</div></div>`;
}
function renderPatientTools(){return`<div class="patient-tools"><label class="label" for="patient-select">Patient workspace</label><select id="patient-select">${state.patients.map(p=>`<option value="${esc(p.id)}" ${p.id===state.activeId?'selected':''}>${esc(p.lastName)}, ${esc(p.firstName)} — ${esc(p.diagnosis)}</option>`).join('')}</select><div class="quick-actions"><button class="btn small primary" data-tab-jump="newpatient">New patient</button><button class="btn small" data-tab-jump="scenarios">Samples</button></div></div>`;}
function renderNav(){
  const groups=[['Chart review',[['summary','PS','Patient summary'],['orders','PO','Provider orders'],['labs','LR','Labs / diagnostics']]],['Documentation',[['vitals','VS','Vital signs'],['assessment','FA','Focused assessment'],['meds','MR','MAR'],['io','IO','Intake / output'],['notes','NN','Nursing notes'],['careplan','CP','Care plan'],['education','ED','Education'],['sbar','SB','SBAR / handoff']]],['Learning tools',[['reasoning','CR','Clinical reasoning'],['peerreview','PR','Peer review mode'],['debriefing','DB','Debriefing'],['progress','PT','My progress'],['report','RP','Print report'],['scenarios','SC','Sample scenarios'],['newpatient','NP','Add patient']]],['Faculty tools',[['modulebuilder','MB','Faculty module builder']]]];
  return`<nav class="nav">${groups.map(([g,items])=>`<div class="group">${g}</div>${items.map(([tab,ic,label])=>`<button class="nav-btn ${state.tab===tab?'active':''}" data-tab="${tab}"><span class="nav-ic">${ic}</span>${label}</button>`).join('')}`).join('')}</nav>`;
}
function toolbarButtons(){return`<button class="btn small primary" id="save-local-btn">Save</button><button class="btn small" id="print-report-btn">${tr('printReport')}</button><button class="btn small danger" id="reset-btn">Reset local</button>`;}
function tabTitle(){const t={summary:'Patient summary',orders:'Provider orders',labs:'Labs / diagnostics',vitals:'Vital signs',assessment:'Focused assessment',meds:'Medication administration record',io:'Intake / output',notes:'Nursing notes',careplan:'Care plan',education:'Patient education',sbar:'SBAR / handoff',reasoning:'Clinical reasoning prompts',debriefing:'Simulation debriefing',progress:'My progress tracker',scenarios:'Sample scenarios',newpatient:'Add patient from scratch',dashboard:'Instructor dashboard',statusboard:'Submission status board',peerreview:tr('peer'),report:'Printable chart report',modulebuilder:tr('faculty')};return t[state.tab]||'Patient summary';}
function renderTab(){const map={summary:rSummary,orders:rOrders,labs:rLabs,vitals:rVitals,assessment:rAssessment,meds:rMeds,io:rIO,notes:rNotes,careplan:rCarePlan,education:rEducation,sbar:rSbar,reasoning:rReasoning,debriefing:rDebriefing,progress:rProgress,scenarios:rScenarios,newpatient:rNewPatient,dashboard:rDashboard,statusboard:rStatusBoard,peerreview:rPeerReview,report:rReport,modulebuilder:rModuleBuilder};return(map[state.tab]||rSummary)();}

// ── FEATURE 1: CLINICAL DECISION ALERTS rendered in vitals tab ─────────────
function renderVitalAlerts(vital){
  const alerts=checkVitalAlerts(vital);
  if(!alerts.length)return'';
  return alerts.map(a=>`<div class="notice danger" style="margin-bottom:6px;"><span class="mark">⚠ ALERT</span><span>${esc(a)}</span></div>`).join('');
}

function rSummary(){const p=currentPatient();const c=chartStats(p);const score=completionScore(p);return`${section('Interactive chart readiness',`<div class="metric-row"><div class="metric interactive"><div class="num">${score}%</div><div class="lbl">Completion</div></div><div class="metric interactive"><div class="num">${c.notes}</div><div class="lbl">Notes</div></div><div class="metric interactive"><div class="num">${c.peer}</div><div class="lbl">Peer reviews</div></div><div class="metric interactive"><div class="num">${c.modules}</div><div class="lbl">Faculty modules</div></div></div><div class="actions" style="justify-content:flex-start"><button class="btn small primary" data-tab-jump="vitals">Chart vitals</button><button class="btn small" data-tab-jump="peerreview">Start peer review</button><button class="btn small" data-tab-jump="modulebuilder">Build module</button><button class="btn small" data-tab-jump="report">Preview report</button></div>`)}${section('Safety snapshot',`<div class="notice ${p.acuity==='Critical'?'danger':'info'}"><span class="mark">HCT</span><span><strong>${esc(p.acuity)} acuity.</strong> Allergies: ${esc(p.allergies)}. Monitoring: ${esc(p.monitoring)}.</span></div><div class="grid-4">${field('Patient',`${p.lastName}, ${p.firstName}`)}${field('DOB / Age',`${p.dob} / ${p.age}`)}${field('Location',p.location)}${field('Diagnosis',p.diagnosis)}${field('Code status',p.codeStatus)}${field('Diet',p.diet)}${field('Activity',p.activity)}${field('Lines',p.lines)}</div>`)}${section('Clinical picture',`<p class="text-block"><strong>Chief complaint:</strong> ${esc(p.chiefComplaint)}</p><p class="text-block"><strong>HPI:</strong> ${esc(p.hpi)}</p><p class="text-block"><strong>Background:</strong> ${esc(p.background)}</p>`)}${section('History and objectives',`<div class="grid-2">${field('Past history',p.pastHistory)}${field('Social / contact',`${p.social}\n${p.familyContact}`)}${(p.objectives||[]).map((o,i)=>field(`Objective ${i+1}`,o)).join('')}</div>`)}`;}
function rOrders(){
  const p=currentPatient();
 
  // ── helper: detect if an order is a medication order ──────────────────────
  const MED_CATEGORIES = ['medication','med','drug','iv fluids','iv','infusion','analgesic','antibiotic','new order'];
  const LAB_CATEGORIES = ['lab','labs','diagnostic','diagnostics','imaging','ecg','ekg','x-ray','xray','ct','mri','ultrasound','blood','culture','specimen','radiology'];
 
  function isMedOrder(o){
    const cat=(o.category||'').toLowerCase();
    const ord=(o.order||'').toLowerCase();
    return MED_CATEGORIES.some(k=>cat.includes(k)||ord.startsWith(k));
  }
  function isLabOrder(o){
    const cat=(o.category||'').toLowerCase();
    const ord=(o.order||'').toLowerCase();
    return LAB_CATEGORIES.some(k=>cat.includes(k)||ord.startsWith(k));
  }
 
  const rows = p.orders.map((o,i) => {
    const done = o.nurseCompleted === true;
    const medFlag = isMedOrder(o) ? `<span class="badge teal" style="margin-left:4px;">MAR</span>` : '';
    const labFlag = isLabOrder(o) ? `<span class="badge blue" style="margin-left:4px;">LAB</span>` : '';
    return `<tr style="opacity:${done?'0.55':'1'}">
      <td>
        <input type="checkbox" data-order-complete="${i}" ${done?'checked':''} title="Mark as completed by nurse" style="width:16px;height:16px;cursor:pointer;accent-color:var(--hct-teal);">
      </td>
      <td>${esc(o.category)}${medFlag}${labFlag}</td>
      <td style="${done?'text-decoration:line-through;color:var(--subtle);':''}"><strong>${esc(o.order)}</strong></td>
      <td style="color:var(--muted);font-size:11px;">${esc(o.details)}</td>
      <td><span class="status ${statusClass(o.status)}">${esc(o.status)}</span></td>
      <td>
        ${done
          ? `<span style="color:var(--success);font-size:11px;font-weight:800;">✓ Done</span>`
          : `<button class="btn small primary" data-order-complete="${i}">Mark done</button>`
        }
      </td>
      <td><button class="btn small danger" data-del-order="${i}">Delete</button></td>
    </tr>`;
  }).join('');
 
  const syncBanner = `<div class="notice info">
    <span class="mark">SYNC</span>
    <span>
      Orders tagged <span class="badge teal">MAR</span> automatically appear in the Medication tab.
      Orders tagged <span class="badge blue">LAB</span> automatically appear in the Labs tab.
      Check the ✓ checkbox to mark an order as completed by the nurse.
    </span>
  </div>`;
 
  return syncBanner +
    section('Provider orders',
      table(['✓','Category','Order','Details','Status','Nurse action',''],rows)
    ) +
    section('Add order',`
      <div class="form-grid">
        <input id="ord-cat" placeholder="Category (e.g. Medication, Lab, Nursing)">
        <input id="ord-name" placeholder="Order">
        <input id="ord-details" placeholder="Details / parameters">
        <select id="ord-status"><option>Active</option><option>STAT</option><option>Pending</option><option>Complete</option></select>
      </div>
      <div class="actions"><button class="btn primary" id="add-order">Add order</button></div>
    `);
}
function rLabs(){
  const p = currentPatient();
 
  const LAB_CATEGORIES = ['lab','labs','diagnostic','diagnostics','imaging','ecg','ekg','x-ray','xray','ct','mri','ultrasound','blood','culture','specimen','radiology'];
  function isLabOrder(o){
    const cat=(o.category||'').toLowerCase();
    const ord=(o.order||'').toLowerCase();
    return LAB_CATEGORIES.some(k=>cat.includes(k)||ord.startsWith(k));
  }
  
// ── Build synced lab entries from orders ──────────────────────────────────
  const existingLabTests = new Set((p.labs||[]).map(l=>(l.test||'').toLowerCase().trim()));
 
  const syncedFromOrders = (p.orders||[])
    .filter(o => isLabOrder(o) && !existingLabTests.has((o.order||'').toLowerCase().trim()))
    .map((o, idx) => ({
      time: o.nurseCompleted ? 'Collected' : 'Pending collection',
      test: o.order,
      result: o.nurseCompleted ? '— (result pending)' : '— (not yet collected)',
      range: o.details || '',
      flag: o.nurseCompleted ? 'Pending' : 'Pending',
      note: `Auto-synced from orders. Status: ${o.status}`,
      _fromOrder: true,
    }));
 
  // Combined: manual labs first, then synced
  const allLabs = [...(p.labs||[]), ...syncedFromOrders];
 
  const rows = allLabs.map((l, i) => {
    const isSync = !!l._fromOrder;
    const syncTag = isSync
      ? `<span class="badge blue" style="margin-left:4px;font-size:9px;">From orders</span>`
      : '';
    return `<tr style="${isSync?'opacity:0.7;':''}">
      <td>${esc(l.time)}</td>
      <td>${esc(l.test)}${syncTag}</td>
      <td><strong style="${isSync?'color:var(--subtle);':''}">${esc(l.result)}</strong></td>
      <td style="color:var(--muted);font-size:11px;">${esc(l.range)}</td>
      <td><span class="status ${statusClass(l.flag)}">${esc(l.flag)}</span></td>
      <td style="font-size:11px;color:var(--muted);">${esc(l.note)}</td>
      <td>
        ${isSync
          ? `<span style="font-size:10px;color:var(--subtle);">Auto</span>`
          : `<button class="btn small danger" data-del-lab="${i}">Delete</button>`
        }
      </td>
    </tr>`;
  }).join('');
 
  const hasSynced = syncedFromOrders.length > 0;
 
  return section('Labs and diagnostics',
    (hasSynced ? `<div class="notice info"><span class="mark">SYNC</span><span><strong>${syncedFromOrders.length} lab/diagnostic order(s)</strong> auto-populated from Provider Orders. Once results are available, add them manually using the form below — they will replace the placeholder rows.</span></div>` : '') +
    table(['Time','Test','Result','Range','Flag','Note',''], rows)
  ) +
  section('Add lab result',`
    <div class="form-grid">
      <input id="lab-time" type="time" value="${nowTime()}">
      <input id="lab-test" placeholder="Test">
      <input id="lab-result" placeholder="Result">
      <select id="lab-flag"><option>Normal</option><option>High</option><option>Low</option><option>Critical</option><option>Pending</option></select>
    </div>
    <div class="form-row"><label>Range / note</label>
      <div class="grid-2">
        <input id="lab-range" placeholder="Reference range">
        <input id="lab-note" placeholder="Clinical note">
      </div>
    </div>
    <div class="actions"><button class="btn primary" id="add-lab">Add result</button></div>
  `);
}

function rVitals(){
  const p = currentPatient();
  const last = p.vitals[p.vitals.length - 1] || {};
 
  // ── Helpers ────────────────────────────────────────────────────────────────
  function fToC(f){
    const n = parseFloat(f);
    return isNaN(n) ? null : Math.round((n - 32) * 5/9 * 10) / 10;
  }
  function displayC(v){
    const c = fToC(v);
    return c !== null ? c.toFixed(1) + ' °C' : '--';
  }
 
  // ── Build alert set from last vitals ──────────────────────────────────────
  function vitalAlertsFull(vital){
    if(!vital || !Object.keys(vital).length) return [];
    const check = {
      hr:    Number(vital.hr),
      bps:   Number(vital.bps),
      bpd:   Number(vital.bpd),
      rr:    Number(vital.rr),
      spo2:  Number(vital.spo2),
      tempc: fToC(vital.temp),
    };
    return VITAL_RULES
      .filter(r => {
        const v = check[r.key];
        return v !== null && !isNaN(v) && (v < r.lo || v > r.hi);
      })
      .map(r => ({
        label: r.label,
        value: r.key === 'tempc'
          ? (check.tempc !== null ? check.tempc.toFixed(1) + ' °C' : '--')
          : (check[r.key] + ' ' + r.unit),
        msg: r.msg,
        critical: r.key === 'spo2' || r.key === 'hr' || r.key === 'bps',
      }));
  }
 
  const alerts = vitalAlertsFull(last);
  const alertHTML = alerts.length
    ? alerts.map(a => `
        <div class="notice ${a.critical ? 'danger' : 'warning'}" style="margin-bottom:6px;">
          <span class="mark">⚠ ${esc(a.label)}: ${esc(a.value)}</span>
          <span>${esc(a.msg)}</span>
        </div>`).join('')
    : '';
 
  // ── Metric tiles ──────────────────────────────────────────────────────────
  const tempC = fToC(last.temp);
  const tempOk = tempC !== null && tempC >= 36.1 && tempC <= 37.9;
  const tempColor = tempC !== null && !tempOk ? 'color:var(--danger);' : '';
 
  const metricTiles = `
    <div class="metric"><div class="num">${esc(last.hr || '--')}</div><div class="lbl">HR (bpm)</div></div>
    <div class="metric"><div class="num">${esc(last.bps || '--')}/${esc(last.bpd || '--')}</div><div class="lbl">BP (mmHg)</div></div>
    <div class="metric"><div class="num">${esc(last.rr || '--')}</div><div class="lbl">RR (br/min)</div></div>
    <div class="metric"><div class="num">${esc(last.spo2 || '--')}%</div><div class="lbl">SpO₂</div></div>
    <div class="metric"><div class="num" style="${tempColor}">${tempC !== null ? tempC.toFixed(1) : '--'} °C</div><div class="lbl">Temp (°C)</div></div>
    <div class="metric"><div class="num">${esc(last.pain || '--')}</div><div class="lbl">Pain (0–10)</div></div>
  `;
 
  // ── Flowsheet rows ────────────────────────────────────────────────────────
  const rows = p.vitals.map((v, i) => {
    const tc = fToC(v.temp);
    return `<tr>
      <td>${esc(v.time)}</td>
      <td>${esc(v.hr)}</td>
      <td>${esc(v.bps)}/${esc(v.bpd)}</td>
      <td>${esc(v.rr)}</td>
      <td>${esc(v.spo2)}%</td>
      <td>${tc !== null ? tc.toFixed(1) + ' °C' : '--'}</td>
      <td>${esc(v.pain)}</td>
      <td>${esc(v.fetal)}</td>
      <td style="font-size:11px;color:var(--muted);">${esc(v.note)}</td>
      <td><button class="btn small danger" data-del-vital="${i}">Delete</button></td>
    </tr>`;
  }).join('');
 
  // ── Legend items for the expanded chart ───────────────────────────────────
  const chartLegend = `
    <div class="vital-legend">
      <span class="vl-hr">■ HR</span>
      <span class="vl-bp">■ SBP</span>
      <span class="vl-dbp">■ DBP</span>
      <span class="vl-rr">■ RR</span>
      <span class="vl-temp">■ Temp °C</span>
      <span class="vl-spo2">■ SpO₂ %</span>
    </div>`;
 
  return `
    <div class="metric-row" style="grid-template-columns:repeat(6,minmax(100px,1fr));">
      ${metricTiles}
    </div>
 
    ${alerts.length ? section('⚠ Clinical decision alerts', alertHTML) : ''}
 
    ${section('Vital trend — 6-parameter chart', `
      <svg class="vital-chart" viewBox="0 0 760 260" style="height:240px;">${vitalSvg(p.vitals)}</svg>
      ${chartLegend}
    `)}
 
    ${section('Flowsheet', table(
      ['Time','HR','BP','RR','SpO₂','Temp','Pain','Specialty','Note',''],
      rows
    ))}
 
    ${section('Add vital signs', `
      <div class="form-grid">
        <input id="vt-time" type="time" value="${nowTime()}">
        <input id="vt-hr"   type="number" placeholder="HR (bpm)">
        <input id="vt-bps"  type="number" placeholder="SBP (mmHg)">
        <input id="vt-bpd"  type="number" placeholder="DBP (mmHg)">
        <input id="vt-rr"   type="number" placeholder="RR (br/min)">
        <input id="vt-temp" placeholder="Temp — enter °C (e.g. 37.2)">
        <input id="vt-spo2" type="number" placeholder="SpO₂ (%)">
        <input id="vt-pain" placeholder="Pain (0–10)">
      </div>
      <div class="form-row">
        <label>Specialty / note</label>
        <div class="grid-2">
          <input id="vt-fetal" placeholder="FHR, peak flow, neuro, or N/A">
          <input id="vt-note"  placeholder="Patient response or cue">
        </div>
      </div>
      <div class="actions">
        <button class="btn primary" id="add-vital">Add vital signs</button>
      </div>
    `)}
  `;
}

