  document.getElementById('save-reasoning')?.addEventListener('click',()=>{const prompts=getPrompts(p.scenarioId);if(!p.reasoningResponses)p.reasoningResponses={};prompts.forEach((_,i)=>{const ta=document.getElementById(`rr-${i}`);if(ta)p.reasoningResponses[i]=ta.value.trim();});persist();toast('Reasoning responses saved');});
