  document.getElementById('save-debrief-fac')?.addEventListener('click',()=>{if(!p.debriefing)p.debriefing={};p.debriefing.facilNotes=val('db-fac-notes');persist();toast('Facilitator notes saved');});
  // Scenarios and new patient
  document.querySelectorAll('[data-load-scenario]').forEach(b=>b.onclick=()=>{const sc=scenarios.find(s=>s.id===b.dataset.loadScenario);const next=clone(sc.patient);next.id=uid(sc.id);state.patients.push(next);state.activeId=next.id;state.tab='summary';persist();render();});
  document.getElementById('create-patient')?.addEventListener('click',()=>{const first=val('np-first'),last=val('np-last'),diagnosis=val('np-diagnosis');if(!first||!last||!diagnosis)return toast('First, last, and diagnosis required');const pNew=patientTemplate({id:uid('patient'),scenarioId:'scratch',firstName:first,lastName:last,age:val('np-age'),sex:val('np-sex'),dob:val('np-dob'),mrn:val('np-mrn')||randomMrn(),location:val('np-location'),diagnosis,acuity:val('np-acuity'),allergies:val('np-allergies')||'NKDA',codeStatus:val('np-code')||'Full Code',tags:(val('np-tags')||'HCT').split(',').map(t=>t.trim()).filter(Boolean),chiefComplaint:val('np-cc')||diagnosis,hpi:val('np-hpi'),background:val('np-bg'),gestation:val('np-gestation')||'N/A'});state.patients.push(pNew);state.activeId=pNew.id;state.tab='summary';persist();render();});
